import{_ as t,o as a,c as r,ae as n}from"./chunks/framework.CHRjkDA5.js";const o="/pr-preview/pr-15/bench.webp",i="/pr-preview/pr-15/tests.webp",s="/pr-preview/pr-15/coverage.webp",b=JSON.parse('{"title":"Frequently asked questions (FAQ)","description":"Frequently asked questions about Elena, Progressive Web Components, browser support, and common patterns.","frontmatter":{"title":"Frequently asked questions (FAQ)","description":"Frequently asked questions about Elena, Progressive Web Components, browser support, and common patterns.","head":[["meta",{"property":"og:title","content":"Frequently asked questions (FAQ) | Elena"}],["meta",{"property":"og:description","content":"Frequently asked questions about Elena, Progressive Web Components, browser support, and common patterns."}],["meta",{"name":"twitter:description","content":"Frequently asked questions about Elena, Progressive Web Components, browser support, and common patterns."}]]},"headers":[{"level":2,"title":"What is Elena?","slug":"what-is-elena","link":"#what-is-elena","children":[]},{"level":2,"title":"Can I build normal web components with Elena?","slug":"can-i-build-normal-web-components-with-elena","link":"#can-i-build-normal-web-components-with-elena","children":[]},{"level":2,"title":"Why was Elena created?","slug":"why-was-elena-created","link":"#why-was-elena-created","children":[]},{"level":2,"title":"Why should I use Elena?","slug":"why-should-i-use-elena","link":"#why-should-i-use-elena","children":[]},{"level":2,"title":"What is a Progressive Web Component?","slug":"what-is-a-progressive-web-component","link":"#what-is-a-progressive-web-component","children":[]},{"level":2,"title":"How does Elena compare against other tools?","slug":"how-does-elena-compare-against-other-tools","link":"#how-does-elena-compare-against-other-tools","children":[{"level":3,"title":"Elena vs Lit","slug":"elena-vs-lit","link":"#elena-vs-lit","children":[]},{"level":3,"title":"Elena vs Stencil","slug":"elena-vs-stencil","link":"#elena-vs-stencil","children":[]}]},{"level":2,"title":"What is the performance compared to Lit?","slug":"what-is-the-performance-compared-to-lit","link":"#what-is-the-performance-compared-to-lit","children":[]},{"level":2,"title":"How is Elena tested?","slug":"how-is-elena-tested","link":"#how-is-elena-tested","children":[]},{"level":2,"title":"What is the browser support?","slug":"what-is-the-browser-support","link":"#what-is-the-browser-support","children":[]},{"level":2,"title":"Can I use Elena in any project?","slug":"can-i-use-elena-in-any-project","link":"#can-i-use-elena-in-any-project","children":[]},{"level":2,"title":"Does Elena require a build step?","slug":"does-elena-require-a-build-step","link":"#does-elena-require-a-build-step","children":[]},{"level":2,"title":"Can I use Elena with TypeScript?","slug":"can-i-use-elena-with-typescript","link":"#can-i-use-elena-with-typescript","children":[]},{"level":2,"title":"Does Elena support server-side rendering?","slug":"does-elena-support-server-side-rendering","link":"#does-elena-support-server-side-rendering","children":[]},{"level":2,"title":"How does Elena handle accessibility?","slug":"how-does-elena-handle-accessibility","link":"#how-does-elena-handle-accessibility","children":[]},{"level":2,"title":"Is Elena production-ready?","slug":"is-elena-production-ready","link":"#is-elena-production-ready","children":[]},{"level":2,"title":"What are you using to generate the documentation?","slug":"what-are-you-using-to-generate-the-documentation","link":"#what-are-you-using-to-generate-the-documentation","children":[]},{"level":2,"title":"How do you version Elena?","slug":"how-do-you-version-elena","link":"#how-do-you-version-elena","children":[]},{"level":2,"title":"Can I sponsor Elena?","slug":"can-i-sponsor-elena","link":"#can-i-sponsor-elena","children":[]},{"level":2,"title":"How can I contribute?","slug":"how-can-i-contribute","link":"#how-can-i-contribute","children":[]},{"level":2,"title":"I found a bug. How do I report it?","slug":"i-found-a-bug-how-do-i-report-it","link":"#i-found-a-bug-how-do-i-report-it","children":[]},{"level":2,"title":"I couldn’t find an answer to my question?","slug":"i-couldn-t-find-an-answer-to-my-question","link":"#i-couldn-t-find-an-answer-to-my-question","children":[]}],"relativePath":"advanced/faq.md","filePath":"advanced/faq.md","lastUpdated":1774985436000}'),l={name:"advanced/faq.md"};function d(c,e,h,p,u,m){return a(),r("div",null,[...e[0]||(e[0]=[n('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /pr-preview/pr-15/advanced/faq.md for this page in Markdown format</div><h1 id="frequently-asked-questions-faq" tabindex="-1">Frequently asked questions (FAQ) <a class="header-anchor" href="#frequently-asked-questions-faq" aria-label="Permalink to &quot;Frequently asked questions (FAQ)&quot;">​</a></h1><h2 id="what-is-elena" tabindex="-1">What is Elena? <a class="header-anchor" href="#what-is-elena" aria-label="Permalink to &quot;What is Elena?&quot;">​</a></h2><p><strong>Elena is a simple, tiny library (2.6kB) for building <a href="/pr-preview/pr-15/components/overview">Progressive Web Components</a>.</strong> Unlike most web component libraries, Elena doesn’t force JavaScript for everything. You can load HTML and CSS first, then use JavaScript to progressively add interactivity.</p><h2 id="can-i-build-normal-web-components-with-elena" tabindex="-1">Can I build normal web components with Elena? <a class="header-anchor" href="#can-i-build-normal-web-components-with-elena" aria-label="Permalink to &quot;Can I build normal web components with Elena?&quot;">​</a></h2><p><a href="/pr-preview/pr-15/components/overview">Progressive Web Components</a> is a design philosophy rather than a library feature. This means that Elena supports building any kind of web component and you have the freedom to choose how to build yours.</p><p>The full standard custom element lifecycle and features such as <code>open</code> or <code>closed</code> Shadow DOM, <code>&lt;template&gt;</code>, <code>&lt;slot&gt;</code> and even <a href="/pr-preview/pr-15/components/templates#declarative-shadow-dom">Declarative Shadow DOM</a> are all supported out of the box with Elena.</p><h2 id="why-was-elena-created" tabindex="-1">Why was Elena created? <a class="header-anchor" href="#why-was-elena-created" aria-label="Permalink to &quot;Why was Elena created?&quot;">​</a></h2><p>Elena was created by <a href="https://arielsalminen.com" target="_blank" rel="noreferrer">@arielle</a> after nearly a decade of building enterprise-scale design systems with <a href="https://arielsalminen.com/2019/why-we-use-web-components/" target="_blank" rel="noreferrer">web components</a>. The recurring pain points were often similar: accessibility issues, server-side rendering, layout shifts, flash of invisible content, React Server Components, too much reliance on client-side JavaScript, and compatibility with e.g. third-party analytics tools.</p><p>Elena was built to solve these problems while staying grounded in web standards and what the platform natively provides. This is how <em>“Progressive Web Components”</em> were born.</p><h2 id="why-should-i-use-elena" tabindex="-1">Why should I use Elena? <a class="header-anchor" href="#why-should-i-use-elena" aria-label="Permalink to &quot;Why should I use Elena?&quot;">​</a></h2><p><strong>Elena is built for teams creating component libraries and design systems.</strong> If you need web components that work across multiple frameworks (such as <a href="https://react.dev" target="_blank" rel="noreferrer">React</a>, <a href="https://nextjs.org" target="_blank" rel="noreferrer">Next.js</a>, <a href="https://vuejs.org" target="_blank" rel="noreferrer">Vue</a>, <a href="https://angular.dev" target="_blank" rel="noreferrer">Angular</a>), render HTML and CSS before JavaScript loads, and sidestep common issues like accessibility problems, SSR limitations, and layout shifts, Elena is built for exactly that.</p><p>It handles the cross-framework complexity (prop/attribute syncing, event delegation, framework compatibility) so you can focus on building components rather than plumbing.</p><h2 id="what-is-a-progressive-web-component" tabindex="-1">What is a Progressive Web Component? <a class="header-anchor" href="#what-is-a-progressive-web-component" aria-label="Permalink to &quot;What is a Progressive Web Component?&quot;">​</a></h2><p>A <a href="/pr-preview/pr-15/components/overview">Progressive Web Component</a> is a native Custom Element designed in two layers: a base layer of HTML and CSS that renders immediately, without JavaScript, and an enhancement layer of JavaScript that adds reactivity, event handling, and more advanced templating.</p><h2 id="how-does-elena-compare-against-other-tools" tabindex="-1">How does Elena compare against other tools? <a class="header-anchor" href="#how-does-elena-compare-against-other-tools" aria-label="Permalink to &quot;How does Elena compare against other tools?&quot;">​</a></h2><h3 id="elena-vs-lit" tabindex="-1">Elena vs Lit <a class="header-anchor" href="#elena-vs-lit" aria-label="Permalink to &quot;Elena vs Lit&quot;">​</a></h3><p><a href="https://lit.dev" target="_blank" rel="noreferrer">Lit</a> is the most widely used web component library and a natural comparison point. Both share a similar foundation, extending native custom elements with tagged template literals for rendering, but differ significantly in approach:</p><div class="table-container"><table><thead><tr><th></th><th>Elena</th><th>Lit</th></tr></thead><tbody><tr><td><strong>DOM model</strong></td><td>Light DOM (Shadow DOM opt-in)</td><td>Shadow DOM</td></tr><tr><td><strong>Size</strong></td><td>2.6kB</td><td>~5kB</td></tr><tr><td><strong>Templating</strong></td><td>Native tagged template literals with auto-escaping</td><td>Custom reactive template engine with directives and binding syntax</td></tr><tr><td><strong>Progressive enhancement</strong></td><td>HTML &amp; CSS first, JavaScript enhances after</td><td>Requires JavaScript for rendering</td></tr><tr><td><strong>SSR</strong></td><td>Works out of the box; optional <code>@elenajs/ssr</code> for components with <code>render()</code></td><td>Requires <code>@lit-labs/ssr</code></td></tr><tr><td><strong>Style encapsulation</strong></td><td><code>@scope</code> + <code>all: unset</code> (Shadow DOM opt-in)</td><td>Shadow DOM (<code>:host</code>, CSS parts)</td></tr><tr><td><strong>Prop reflection</strong></td><td>Reflects all; disable per-prop</td><td>Reflects none; enable per-prop</td></tr><tr><td><strong>Accessibility</strong></td><td>Full Light DOM access</td><td>Shadow DOM accessibility limitations</td></tr><tr><td><strong>API</strong></td><td>Static class fields + reactive properties</td><td>Decorators + reactive properties</td></tr></tbody></table></div><p>The biggest philosophical difference is the DOM model. Lit uses Shadow DOM by default for strong encapsulation; Elena uses Light DOM by default for accessibility, SSR, and CSS inheritance, with Shadow DOM available as an opt-in.</p><p>On the templating side, both use <code>html</code> tagged template literals, but Lit has a custom reactive template engine. Elena, on the other hand, provides just a thin wrapper around the native template literals.</p><h3 id="elena-vs-stencil" tabindex="-1">Elena vs Stencil <a class="header-anchor" href="#elena-vs-stencil" aria-label="Permalink to &quot;Elena vs Stencil&quot;">​</a></h3><p><a href="https://stenciljs.com" target="_blank" rel="noreferrer">Stencil</a> is a compiler that generates native web components, developed by the Ionic team. Unlike runtime libraries like Elena or Lit, Stencil is primarily a build tool. Components are authored in TypeScript + JSX and compiled to standalone custom elements:</p><div class="table-container"><table><thead><tr><th></th><th>Elena</th><th>Stencil</th></tr></thead><tbody><tr><td><strong>Approach</strong></td><td>Runtime mixin</td><td>Compiler</td></tr><tr><td><strong>Language</strong></td><td>Vanilla JavaScript or TypeScript</td><td>TypeScript + JSX</td></tr><tr><td><strong>Build step</strong></td><td>Optional</td><td>Required</td></tr><tr><td><strong>Templating</strong></td><td>Native tagged template literals with auto-escaping</td><td>JSX (compiled via TypeScript)</td></tr><tr><td><strong>DOM model</strong></td><td>Light DOM (Shadow DOM opt-in)</td><td>Shadow DOM (default; configurable)</td></tr><tr><td><strong>Progressive enhancement</strong></td><td>HTML &amp; CSS first, JavaScript enhances after</td><td>Requires JavaScript for rendering</td></tr><tr><td><strong>SSR</strong></td><td>Works out of the box; optional <code>@elenajs/ssr</code> for components with <code>render()</code></td><td>Requires Stencil’s Hydrate app</td></tr><tr><td><strong>Prop reflection</strong></td><td>Reflects all; disable per-prop</td><td>Reflects none; enable per-prop</td></tr><tr><td><strong>Style encapsulation</strong></td><td><code>@scope</code> + <code>all: unset</code></td><td>Shadow DOM or scoped CSS</td></tr><tr><td><strong>API</strong></td><td>Static class fields + reactive properties</td><td>Decorators + JSX</td></tr><tr><td><strong>Output targets</strong></td><td>Not necessary</td><td>Custom elements, React, Angular, Vue wrappers</td></tr></tbody></table></div><p>Stencil’s standout feature is its output targets: it can generate framework-specific wrappers (React, Angular, Vue) automatically from the same component source. If you need generated bindings for multiple frameworks, Stencil has a clear advantage. Elena, by contrast, works directly with any framework without generated wrappers.</p><h2 id="what-is-the-performance-compared-to-lit" tabindex="-1">What is the performance compared to Lit? <a class="header-anchor" href="#what-is-the-performance-compared-to-lit" aria-label="Permalink to &quot;What is the performance compared to Lit?&quot;">​</a></h2><p>At the time of writing, the performance is very similar in our simulated benchmark tests. According to the benchmarks, Elena is roughly <code>1.20×</code> faster than Lit for single element creation and batch creation of up to 1000 web components <em>(the gap gets smaller though the bigger this number grows, see the below screenshot).</em> Lit is roughly <code>1.19×</code> faster on re-renders via attribute change.</p><p>That said, synthetic benchmarks only measure isolated operations and Lit is much more heavily optimized than Elena. Real-world performance depends on what you’re building: how many components are on the page, how often they re-render, how complex your templates are, and how your styles are structured. Our benchmark tests can’t reveal the full picture.</p><img src="'+o+'" loading="lazy" width="2804" height="1390" alt="Elena bench test suite"><p>When you look at the above screenshot, keep in mind that Elena defaults to Light DOM, Lit to Shadow DOM. Enabling Shadow DOM narrows the gap to only a <code>1.06×</code> performance gain over Lit for single element creation, and batch creation performs identically at a consistent <code>1.00×</code>.</p><h2 id="how-is-elena-tested" tabindex="-1">How is Elena tested? <a class="header-anchor" href="#how-is-elena-tested" aria-label="Permalink to &quot;How is Elena tested?&quot;">​</a></h2><p>Elena has a comprehensive automated test suite with 1000+ tests across 57 test files covering unit tests, integration tests, visual diff tests, and benchmark tests:</p><img src="'+i+'" loading="lazy" width="1636" height="2212" alt="Elena vitest test suite"><p>Additionally, the <code>@elenajs/core</code> library is proud to ship with 100% test coverage across all of its source code:</p><img src="'+s+'" loading="lazy" width="1764" height="1040" alt="Elena vitest coverage report for @elenajs/core"><h2 id="what-is-the-browser-support" tabindex="-1">What is the browser support? <a class="header-anchor" href="#what-is-the-browser-support" aria-label="Permalink to &quot;What is the browser support?&quot;">​</a></h2><p>As a baseline, Elena’s progressive approach supports any web browser that’s capable of rendering Custom Elements. After that, it’s up to you to determine what is appropriate for your project when authoring CSS styles and JavaScript interactivity. Elena, the JavaScript library, supports the following browser versions:</p><ul><li>Chrome 71+</li><li>Firefox 69+</li><li>Safari 12.1+</li><li>Edge 79+</li><li>Opera 58+</li></ul><h2 id="can-i-use-elena-in-any-project" tabindex="-1">Can I use Elena in any project? <a class="header-anchor" href="#can-i-use-elena-in-any-project" aria-label="Permalink to &quot;Can I use Elena in any project?&quot;">​</a></h2><p>Yes. Elena is licensed under the <a href="https://opensource.org/licenses/MIT" target="_blank" rel="noreferrer">MIT License</a>, which means you can use it in personal, commercial, and open source projects. You can modify, distribute, and sublicense it freely. The only requirement is that you include the original copyright notice and license text in any copy or substantial portion of the software.</p><h2 id="does-elena-require-a-build-step" tabindex="-1">Does Elena require a build step? <a class="header-anchor" href="#does-elena-require-a-build-step" aria-label="Permalink to &quot;Does Elena require a build step?&quot;">​</a></h2><p>No. Elena components are vanilla HTML, CSS, and JavaScript and work directly in the browser with a <code>&lt;script type=&quot;module&quot;&gt;</code> tag. No build step, compiler, or transpilation is required. The <code>@elenajs/bundler</code> package is available for production optimization: it minifies CSS and JavaScript, generates a Custom Elements Manifest, and produces TypeScript declarations, but it’s entirely optional.</p><h2 id="can-i-use-elena-with-typescript" tabindex="-1">Can I use Elena with TypeScript? <a class="header-anchor" href="#can-i-use-elena-with-typescript" aria-label="Permalink to &quot;Can I use Elena with TypeScript?&quot;">​</a></h2><p>Yes. Elena itself is written in vanilla JavaScript with JSDoc type annotations, but the <code>@elenajs/bundler</code> supports <code>.ts</code> component files out of the box. Running <code>elena build</code> on a TypeScript project will transpile your components and generate per-component <code>.d.ts</code> declaration files automatically.</p><h2 id="does-elena-support-server-side-rendering" tabindex="-1">Does Elena support server-side rendering? <a class="header-anchor" href="#does-elena-support-server-side-rendering" aria-label="Permalink to &quot;Does Elena support server-side rendering?&quot;">​</a></h2><p>Yes. Elena’s approach to server-side rendering is simple and straightforward. Since <a href="/pr-preview/pr-15/components/overview">Progressive Web Components</a> are primarily HTML and CSS, you don’t need any special logic on the server to render them.</p><p>Components without a <code>render()</code> method are fully SSR-compatible by default, while components with <code>render()</code> provide partial support and complete hydration on the client side.</p><p>The “partial support” for the latter means that you can render the initial state without JavaScript, but JS is needed for the interactivity <em>(unless you also use the provided <a href="/pr-preview/pr-15/advanced/ssr#rendering-to-html-strings">@elenajs/ssr</a> tool).</em></p><p>Elena also supports <a href="/pr-preview/pr-15/advanced/ssr#declarative-shadow-dom">Declarative Shadow DOM</a> for cases where you may need stronger isolation, but still want the component to render server-side.</p><h2 id="how-does-elena-handle-accessibility" tabindex="-1">How does Elena handle accessibility? <a class="header-anchor" href="#how-does-elena-handle-accessibility" aria-label="Permalink to &quot;How does Elena handle accessibility?&quot;">​</a></h2><p>Elena uses Light DOM by default, which means assistive technologies like screen readers have full access to the component’s content, just like any other HTML element. There are no Shadow DOM boundaries breaking label or ARIA associations unless you explicitly opt-in. Components are built on semantic HTML, so standard accessibility practices apply without workarounds.</p><h2 id="is-elena-production-ready" tabindex="-1">Is Elena production-ready? <a class="header-anchor" href="#is-elena-production-ready" aria-label="Permalink to &quot;Is Elena production-ready?&quot;">​</a></h2><p>Elena is actively maintained, has a comprehensive test suite, and follows <a href="https://semver.org/" target="_blank" rel="noreferrer">Semantic Versioning</a>. It was built from real-world experience shipping enterprise design systems. That said, Elena is still a young project and the API may evolve. Check the <a href="https://github.com/getelena/elena/releases" target="_blank" rel="noreferrer">changelog</a> for the latest updates.</p><h2 id="what-are-you-using-to-generate-the-documentation" tabindex="-1">What are you using to generate the documentation? <a class="header-anchor" href="#what-are-you-using-to-generate-the-documentation" aria-label="Permalink to &quot;What are you using to generate the documentation?&quot;">​</a></h2><p>Elena’s documentation is built with <a href="https://vitepress.dev" target="_blank" rel="noreferrer">VitePress</a>, a static site generator powered by Vite and Vue. The component API references are generated from the <a href="https://custom-elements-manifest.open-wc.org" target="_blank" rel="noreferrer">Custom Elements Manifest</a>, which is produced automatically by Elena’s build tooling.</p><h2 id="how-do-you-version-elena" tabindex="-1">How do you version Elena? <a class="header-anchor" href="#how-do-you-version-elena" aria-label="Permalink to &quot;How do you version Elena?&quot;">​</a></h2><p>Elena follows <a href="https://semver.org/" target="_blank" rel="noreferrer">Semantic Versioning</a>. Under this scheme, version numbers and the way they change convey meaning about the underlying features and what has been modified from one version to the next.</p><h2 id="can-i-sponsor-elena" tabindex="-1">Can I sponsor Elena? <a class="header-anchor" href="#can-i-sponsor-elena" aria-label="Permalink to &quot;Can I sponsor Elena?&quot;">​</a></h2><p>Elena is an MIT-licensed open source project and completely free to use. However, we understand that the project won’t remain sustainable forever without financial backing. Hence, we’re planning to set up sponsorship at <a href="https://opencollective.com/elenajs" target="_blank" rel="noreferrer">Open Collective</a> later.</p><p>If you have questions regarding the <a href="/pr-preview/pr-15/about/sponsor">sponsorship</a>, please reach out to <a href="mailto:hi@elenajs.com" target="_blank" rel="noreferrer">hi@elenajs.com</a>.</p><h2 id="how-can-i-contribute" tabindex="-1">How can I contribute? <a class="header-anchor" href="#how-can-i-contribute" aria-label="Permalink to &quot;How can I contribute?&quot;">​</a></h2><p>See the <a href="https://github.com/getelena/elena/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">contributing guidelines</a> on GitHub.</p><h2 id="i-found-a-bug-how-do-i-report-it" tabindex="-1">I found a bug. How do I report it? <a class="header-anchor" href="#i-found-a-bug-how-do-i-report-it" aria-label="Permalink to &quot;I found a bug. How do I report it?&quot;">​</a></h2><p>First, make sure the bug is reproducible. Once confirmed, <a href="https://github.com/getelena/elena/issues/new/choose" target="_blank" rel="noreferrer">create a new issue</a> on GitHub.</p><h2 id="i-couldn-t-find-an-answer-to-my-question" tabindex="-1">I couldn’t find an answer to my question? <a class="header-anchor" href="#i-couldn-t-find-an-answer-to-my-question" aria-label="Permalink to &quot;I couldn’t find an answer to my question?&quot;">​</a></h2><p>If you couldn’t find an answer to your question, please don’t hesitate to join <a href="https://discord.gg/7WGcdngTD7" target="_blank" rel="noreferrer">Elena’s Discord server</a> to ask questions from the community.</p>',66)])])}const w=t(l,[["render",d]]);export{b as __pageData,w as default};
